// server/cyberForgeController.ts
init_openai();
async function generateLearningContent(theme, userLevel = "d\xE9butant", learningHistory = []) {
  const systemMessage = `Vous \xEAtes un expert en \xE9ducation en cybers\xE9curit\xE9, sp\xE9cialis\xE9 dans la cr\xE9ation de mat\xE9riel p\xE9dagogique interactif. 
Votre mission est de g\xE9n\xE9rer un module d'apprentissage complet sur un sujet de cybers\xE9curit\xE9.

Suivez ces consignes importantes:
1. Cr\xE9ez un contenu adapt\xE9 au niveau '${userLevel}' (d\xE9butant, interm\xE9diaire ou expert).
2. Incluez uniquement des faits et recommandations pr\xE9cis et \xE0 jour.
3. Privil\xE9giez les sources officielles fran\xE7aises comme l'ANSSI et la CNIL.
4. Int\xE9grez des exemples concrets et pertinents pour le contexte professionnel.
5. Structurez clairement l'information pour une progression logique.
6. Utilisez un ton professionnel et accessible.

G\xE9n\xE9rez un module d'apprentissage sur "${theme}" qui inclut les sections suivantes:
- Un titre clair et descriptif
- Une introduction engageante qui pr\xE9sente l'importance du sujet
- 5 concepts cl\xE9s essentiels \xE0 comprendre
- Un sc\xE9nario interactif avec au moins 2 \xE9tapes de prise de d\xE9cision, chacune avec plusieurs options et des explications d\xE9taill\xE9es
- 2-3 questions ouvertes pour \xE9valuer la compr\xE9hension, avec des concepts cl\xE9s \xE0 rechercher dans les r\xE9ponses
- 2-4 ressources additionnelles pertinentes et fiables pour approfondir (documentation ANSSI, CNIL, ENISA, etc.)`;
  const userMessage = `Cr\xE9ez un module d'apprentissage interactif sur "${theme}" adapt\xE9 au niveau ${userLevel}.

${learningHistory.length > 0 ? `L'utilisateur a d\xE9j\xE0 compl\xE9t\xE9 ${learningHistory.length} modules, dont: ${learningHistory.slice(0, 3).map((h) => h.moduleId).join(", ")}${learningHistory.length > 3 ? "..." : ""}` : "C'est le premier module que l'utilisateur va suivre."}`;
  try {
    const completion = await openAIService.getChatCompletion([
      { role: "system", content: systemMessage },
      { role: "user", content: userMessage }
    ]);
    try {
      if (typeof completion === "object") {
        const content2 = completion;
        return ensureContentStructure(content2, theme);
      }
      const content = JSON.parse(completion);
      return ensureContentStructure(content, theme);
    } catch (parseError) {
      console.error("Erreur de parsing JSON:", parseError);
      const jsonMatch = completion.match(/```json([\s\S]*?)```/) || completion.match(/{[\s\S]*}/);
      if (jsonMatch) {
        try {
          const extractedJson = jsonMatch[1] ? jsonMatch[1].trim() : jsonMatch[0];
          const content = JSON.parse(extractedJson);
          return ensureContentStructure(content, theme);
        } catch (extractError) {
          console.error("Erreur lors de l'extraction JSON:", extractError);
          throw new Error("Le format de la r\xE9ponse est invalide");
        }
      } else {
        throw new Error("Impossible de g\xE9n\xE9rer un contenu correctement structur\xE9");
      }
    }
  } catch (error) {
    console.error("Erreur lors de la g\xE9n\xE9ration de contenu:", error);
    throw error;
  }
}
function ensureContentStructure(content, theme) {
  return {
    title: content.title || `Module sur ${theme}`,
    introduction: content.introduction || `<p>Bienvenue dans ce module sur ${theme}.</p>`,
    concepts_cl\u00E9s: Array.isArray(content.concepts_cl\u00E9s) ? content.concepts_cl\u00E9s : [],
    scenario_interactif: {
      titre: content.scenario_interactif?.titre || "Mise en situation professionnelle",
      contexte: content.scenario_interactif?.contexte || "Vous \xEAtes confront\xE9 \xE0 un d\xE9fi de cybers\xE9curit\xE9.",
      etapes: Array.isArray(content.scenario_interactif?.etapes) ? content.scenario_interactif.etapes : []
    },
    questions: Array.isArray(content.questions) ? content.questions : [],
    ressources_additionnelles: Array.isArray(content.ressources_additionnelles) ? content.ressources_additionnelles : []
  };
}
async function evaluateUserResponse(userResponse, context, expectedConcepts = []) {
  const systemMessage = `Vous \xEAtes un \xE9valuateur expert en cybers\xE9curit\xE9, charg\xE9 d'\xE9valuer les r\xE9ponses des apprenants \xE0 des questions de formation.

Suivez ces consignes:
1. \xC9valuez objectivement si la r\xE9ponse d\xE9montre une compr\xE9hension des concepts cl\xE9s attendus
2. Attribuez un score de 0 \xE0 1 (0 = compr\xE9hension minimale, 1 = excellente compr\xE9hension)
3. Fournissez un feedback constructif et pr\xE9cis
4. Identifiez les forces de la r\xE9ponse (maximum 3)
5. Sugg\xE9rez des points d'am\xE9lioration (maximum 3)
6. Expliquez bri\xE8vement votre \xE9valuation

R\xE9pondez UNIQUEMENT au format JSON avec les champs suivants:
{
  "score": (nombre entre 0 et 1),
  "feedback": (commentaire g\xE9n\xE9ral),
  "strengths": [(liste des points forts)],
  "areas_to_improve": [(liste des points \xE0 am\xE9liorer)],
  "explanation": (explication de l'\xE9valuation)
}`;
  const userMessage = `Question: ${context}

R\xE9ponse de l'apprenant: "${userResponse}"

Concepts cl\xE9s attendus: ${expectedConcepts.join(", ")}

\xC9valuez cette r\xE9ponse selon les crit\xE8res demand\xE9s. R\xE9pondez uniquement au format JSON sp\xE9cifi\xE9.`;
  try {
    const completion = await openAIService.getChatCompletion([
      { role: "system", content: systemMessage },
      { role: "user", content: userMessage }
    ]);
    try {
      if (typeof completion === "object") {
        return completion;
      }
      return JSON.parse(completion);
    } catch (parseError) {
      console.error("Erreur de parsing JSON:", parseError);
      const jsonMatch = completion.match(/```json([\s\S]*?)```/) || completion.match(/{[\s\S]*}/);
      if (jsonMatch) {
        try {
          const extractedJson = jsonMatch[1] ? jsonMatch[1].trim() : jsonMatch[0];
          return JSON.parse(extractedJson);
        } catch (extractError) {
          console.error("Erreur lors de l'extraction JSON:", extractError);
        }
      }
      return {
        score: 0.5,
        feedback: "Impossible d'\xE9valuer pr\xE9cis\xE9ment votre r\xE9ponse.",
        strengths: ["Effort de r\xE9ponse"],
        areas_to_improve: ["Structurer davantage la r\xE9ponse", "Aborder les concepts cl\xE9s attendus"],
        explanation: "\xC9valuation par d\xE9faut due \xE0 une erreur technique."
      };
    }
  } catch (error) {
    console.error("Erreur lors de l'\xE9valuation:", error);
    throw error;
  }
}

