// server/routes/audioRoutes.ts
import express3 from "express";

// server/services/azureSpeech.ts
import * as sdk from "microsoft-cognitiveservices-speech-sdk";
import { PassThrough } from "stream";
var AzureSpeechService = class {
  speechConfig;
  constructor() {
    const speechKey = process.env.AZURE_SPEECH_KEY;
    const speechRegion = process.env.AZURE_SPEECH_REGION;
    if (!speechKey || !speechRegion) {
      console.warn("Azure Speech non configur\xE9 (AZURE_SPEECH_KEY/AZURE_SPEECH_REGION manquants) \u2014 fonctionnalit\xE9 d\xE9sactiv\xE9e");
      return;
    }
    this.speechConfig = sdk.SpeechConfig.fromSubscription(speechKey, speechRegion);
    this.speechConfig.speechSynthesisVoiceName = "fr-FR-HenriNeural";
    this.speechConfig.speechSynthesisOutputFormat = sdk.SpeechSynthesisOutputFormat.Audio16Khz32KBitRateMonoMp3;
  }
  // Convertir du texte en flux audio MP3
  async textToSpeechStream(options) {
    const { text: text2, voiceName, language, style } = options;
    if (voiceName) {
      this.speechConfig.speechSynthesisVoiceName = voiceName;
    }
    let ssmlText = "";
    if (style) {
      ssmlText = `<speak version="1.0" xmlns="http://www.w3.org/2001/10/synthesis" xmlns:mstts="https://www.w3.org/2001/mstts" xml:lang="${language || "fr-FR"}">
        <voice name="${this.speechConfig.speechSynthesisVoiceName}">
          <mstts:express-as style="${style}">
            ${text2}
          </mstts:express-as>
        </voice>
      </speak>`;
    }
    return new Promise((resolve, reject) => {
      const pullStream = sdk.AudioOutputStream.createPullStream();
      const synthesizer = new sdk.SpeechSynthesizer(this.speechConfig, sdk.AudioConfig.fromStreamOutput(pullStream));
      const audioStream = new PassThrough();
      let dataLength = 0;
      synthesizer.synthesisStarted = () => {
        console.log("Synth\xE8se vocale d\xE9marr\xE9e");
      };
      synthesizer.synthesizing = (_sender, _event) => {
      };
      const processAudio = (audioBuffer) => {
        const audioData = Buffer.from(audioBuffer);
        dataLength += audioData.length;
        audioStream.write(audioData);
      };
      synthesizer.synthesisCompleted = async (_sender, event) => {
        console.log("Synth\xE8se vocale termin\xE9e");
        const audioBuffer = new ArrayBuffer(16e3);
        let pullResult = await pullStream.read(audioBuffer);
        while (pullResult.length > 0) {
          processAudio(audioBuffer.slice(0, pullResult.length));
          pullResult = await pullStream.read(audioBuffer);
        }
        audioStream.end();
        synthesizer.close();
        resolve({ audioStream, contentLength: dataLength });
      };
      synthesizer.SynthesisCanceled = (_sender, event) => {
        const cancellationDetails = sdk.SpeechSynthesisCancellationDetails.fromResult(event.result);
        console.error(`Synth\xE8se vocale annul\xE9e: ${cancellationDetails.reason}`);
        if (cancellationDetails.reason === sdk.CancellationReason.Error) {
          console.error(`Code d'erreur: ${cancellationDetails.errorCode}`);
          console.error(`D\xE9tails de l'erreur: ${cancellationDetails.errorDetails}`);
        }
        audioStream.end();
        synthesizer.close();
        reject(new Error(`Synth\xE8se vocale annul\xE9e: ${cancellationDetails.errorDetails}`));
      };
      if (style) {
        synthesizer.speakSsmlAsync(
          ssmlText,
          (result) => {
            if (result.errorDetails) {
              console.error(`Erreur de synth\xE8se: ${result.errorDetails}`);
              reject(new Error(result.errorDetails));
            }
          },
          (error) => {
            console.error(`Erreur: ${error}`);
            reject(error);
          }
        );
      } else {
        synthesizer.speakTextAsync(
          text2,
          (result) => {
            if (result.errorDetails) {
              console.error(`Erreur de synth\xE8se: ${result.errorDetails}`);
              reject(new Error(result.errorDetails));
            }
          },
          (error) => {
            console.error(`Erreur: ${error}`);
            reject(error);
          }
        );
      }
    });
  }
  // Fonction pour obtenir les voix disponibles
  async getAvailableVoices() {
    return new Promise((resolve, reject) => {
      const synthesizer = new sdk.SpeechSynthesizer(this.speechConfig);
      synthesizer.getVoicesAsync(
        (result) => {
          synthesizer.close();
          if (result.voices && result.voices.length > 0) {
            resolve(result.voices);
          } else {
            reject(new Error("Aucune voix disponible"));
          }
        },
        (error) => {
          synthesizer.close();
          reject(error);
        }
      );
    });
  }
};
var azureSpeechService = process.env.AZURE_SPEECH_KEY && process.env.AZURE_SPEECH_REGION ? new AzureSpeechService() : null;

// server/routes/audioRoutes.ts
var router6 = express3.Router();
router6.post("/text-to-speech", async (req, res) => {
  try {
    const { text: text2, voiceName, language, style } = req.body;
    if (!text2) {
      return res.status(400).json({ error: "Le texte est requis" });
    }
    if (!azureSpeechService) {
      return res.status(503).json({ error: "Service audio non configur\xE9" });
    }
    const { audioStream, contentLength } = await azureSpeechService.textToSpeechStream({
      text: text2,
      voiceName,
      language,
      style
    });
    res.setHeader("Content-Type", "audio/mpeg");
    res.setHeader("Content-Length", contentLength);
    res.setHeader("Content-Disposition", 'attachment; filename="speech.mp3"');
    audioStream.pipe(res);
  } catch (error) {
    console.error("Erreur lors de la synth\xE8se vocale:", error);
    res.status(500).json({ error: "Erreur lors de la synth\xE8se vocale" });
  }
});
router6.get("/voices", async (_req, res) => {
  try {
    const voices = await azureSpeechService.getAvailableVoices();
    const formattedVoices = voices.map((voice) => ({
      name: voice.name,
      language: voice.locale,
      gender: voice.gender,
      local: voice.localName,
      styles: voice.styleList || []
    }));
    res.json({ voices: formattedVoices });
  } catch (error) {
    console.error("Erreur lors de la r\xE9cup\xE9ration des voix:", error);
    res.status(500).json({ error: "Erreur lors de la r\xE9cup\xE9ration des voix" });
  }
});
var audioRoutes_default = router6;

// server/routes/codeExecutionRoutes.ts
import { Router as Router4 } from "express";
import { exec } from "child_process";
import fs from "fs";
import path from "path";
import os from "os";
import { v4 as uuidv4 } from "uuid";
var router7 = Router4();
var TIMEOUT_MS = 1e4;
router7.post("/execute", async (req, res) => {
  const { code, language } = req.body;
  if (!code || !language) {
    return res.status(400).json({ error: "Code et langage requis" });
  }
  if (code.length > 15e3) {
    return res.status(400).json({ error: "Code trop long (max 15 000 caract\xE8res)" });
  }
  const tmpDir = os.tmpdir();
  const fileId = uuidv4().replace(/-/g, "");
  const startTime = Date.now();
  let filePath;
  let command;
  if (language === "python" || language === "sql") {
    filePath = path.join(tmpDir, `fyne_${fileId}.py`);
    command = `python3 ${filePath}`;
  } else if (language === "javascript") {
    filePath = path.join(tmpDir, `fyne_${fileId}.js`);
    command = `node ${filePath}`;
  } else {
    return res.status(400).json({ error: "Langage non support\xE9" });
  }
  try {
    fs.writeFileSync(filePath, code, "utf8");
  } catch (err) {
    return res.status(500).json({ error: "Impossible d'\xE9crire le fichier temporaire" });
  }
  exec(command, { timeout: TIMEOUT_MS, maxBuffer: 2 * 1024 * 1024 }, (error, stdout, stderr) => {
    try {
      fs.unlinkSync(filePath);
    } catch {
    }
    const executionTime = Date.now() - startTime;
    if (error?.killed) {
      return res.json({
        stdout: "",
        stderr: "\u23F1 D\xE9lai d\xE9pass\xE9 \u2014 ton code tourne depuis plus de 10 secondes. V\xE9rifie les boucles infinies.",
        exitCode: 1,
        executionTime
      });
    }
    return res.json({
      stdout,
      stderr,
      exitCode: error ? error.code ?? 1 : 0,
      executionTime
    });
  });
});
var codeExecutionRoutes_default = router7;

