      id: "sql-fundamentals-section-3",
      title: "Requ\xEAtes SELECT simples",
      type: "code",
      codeLanguage: "sql",
      content: `
-- S\xE9lectionner toutes les colonnes de la table clients
SELECT * FROM clients;

-- S\xE9lectionner des colonnes sp\xE9cifiques
SELECT id, nom, email FROM clients;

-- Utiliser des alias pour renommer les colonnes dans les r\xE9sultats
SELECT 
    id AS client_id,
    nom AS nom_client,
    email AS adresse_email
FROM clients;

-- Filtrer les r\xE9sultats avec WHERE
SELECT * FROM clients
WHERE ville = 'Paris';

-- Combiner plusieurs conditions
SELECT * FROM clients
WHERE ville = 'Paris' AND date_inscription >= '2023-01-01';

-- Utiliser l'op\xE9rateur IN pour une liste de valeurs
SELECT * FROM clients
WHERE ville IN ('Paris', 'Lyon', 'Marseille');

-- Recherche avec LIKE (% = n'importe quel nombre de caract\xE8res)
SELECT * FROM clients
WHERE email LIKE '%@gmail.com';

-- Trier les r\xE9sultats
SELECT * FROM clients
ORDER BY nom ASC;  -- ASC = ascendant (par d\xE9faut), DESC = descendant

-- Limiter le nombre de r\xE9sultats
SELECT * FROM clients
ORDER BY date_inscription DESC
LIMIT 10;  -- R\xE9cup\xE8re seulement les 10 clients les plus r\xE9cents
      `
