      content: `
-- Sous-requ\xEAte dans le WHERE
-- Trouver les clients qui ont pass\xE9 des commandes sup\xE9rieures \xE0 la moyenne
SELECT id, nom, email
FROM clients
WHERE id IN (
    SELECT DISTINCT client_id
    FROM commandes
    WHERE montant > (
        SELECT AVG(montant) FROM commandes
    )
);

-- Sous-requ\xEAte dans le FROM (cr\xE9ation d'une table d\xE9riv\xE9e)
-- Analyser les commandes par trimestre
SELECT 
    trimestre,
    COUNT(*) AS nombre_commandes,
    SUM(montant) AS chiffre_affaires,
    AVG(montant) AS panier_moyen
FROM (
    SELECT 
        EXTRACT(YEAR FROM date_commande) AS annee,
        EXTRACT(QUARTER FROM date_commande) AS trimestre,
        montant
    FROM commandes
    WHERE date_commande >= '2023-01-01'
) AS commandes_trimestrielles
GROUP BY trimestre
ORDER BY trimestre;

-- Sous-requ\xEAte corr\xE9l\xE9e
-- Trouver les produits qui ont \xE9t\xE9 command\xE9s plus que la moyenne de leur cat\xE9gorie
SELECT p.id, p.nom, p.categorie, 
       (SELECT SUM(quantite) FROM details_commande WHERE produit_id = p.id) AS quantite_totale
FROM produits p
WHERE (
    SELECT SUM(quantite) FROM details_commande WHERE produit_id = p.id
) > (
    SELECT AVG(total_cat)
    FROM (
        SELECT p2.categorie, SUM(dc.quantite) AS total_cat
        FROM produits p2
        JOIN details_commande dc ON p2.id = dc.produit_id
        WHERE p2.categorie = p.categorie
        GROUP BY p2.id
    ) AS moyennes_categorie
);

-- Utilisation de EXISTS
-- Trouver les clients qui ont achet\xE9 au moins un produit de la cat\xE9gorie "\xC9lectronique"
SELECT c.id, c.nom
FROM clients c
WHERE EXISTS (
    SELECT 1
    FROM commandes com
    JOIN details_commande dc ON com.id = dc.commande_id
    JOIN produits p ON dc.produit_id = p.id
    WHERE com.client_id = c.id
    AND p.categorie = '\xC9lectronique'
);
      `
