async function generateCourseContent(req, res) {
  const {
    moduleId,
    moduleTitle
  } = req.body;
  if (!moduleId) {
    return res.status(400).json({
      success: false,
      error: "Information du module incompl\xE8te. L'identifiant est requis."
    });
  }
  try {
    const course = dataIaCoursesService.getCourse(moduleId);
    if (!course) {
      return res.status(404).json({
        success: false,
        error: `Aucun cours trouv\xE9 pour le module: ${moduleId}`
      });
    }
    return res.json({
      success: true,
      moduleId,
      moduleTitle: course.title,
      content: course.content,
      sections: course.sections,
      exercises: course.exercises,
      resources: course.resources
    });
  } catch (error) {
    console.error("Erreur lors de la r\xE9cup\xE9ration du cours:", error);
    return res.status(500).json({
      success: false,
      error: "Une erreur est survenue lors de la r\xE9cup\xE9ration du contenu du cours. Veuillez r\xE9essayer."
    });
  }
}
