init_openai();
async function generateSyntheseEntretien(req, res) {
  try {
    const { notes } = req.body;
    if (!notes) {
      return res.status(400).json({
        success: false,
        message: "Les notes d'entretien sont requises"
      });
    }
    const systemMessage = {
      role: "system",
      content: `Tu es un assistant sp\xE9cialis\xE9 dans l'analyse et la structuration de notes d'entretien de recrutement. 
      
Ta t\xE2che est d'analyser les notes fournies par un recruteur et de les transformer en une synth\xE8se structur\xE9e selon un format sp\xE9cifique.

Pour chaque section, extrais les informations pertinentes des notes, formule des phrases compl\xE8tes et professionnelles, et assure-toi que le contenu est coh\xE9rent.

Si tu ne trouves pas d'information pour une section particuli\xE8re, indique "Information non disponible dans les notes fournies."

Voici les sections \xE0 remplir (retourne un objet JSON avec ces champs) :
- presentation: Pr\xE9sentation g\xE9n\xE9rale du profil (formation, exp\xE9riences, trous \xE9ventuels)
- impression: Premi\xE8res impressions, posture
- motivation: Motivation pour le conseil, les SI, et mc2i
- comprehension: Compr\xE9hension de nos m\xE9tiers et renseignement sur le cabinet
- projet: Projet professionnel (court / moyen / long terme)
- potentiel: Potentiel vs ambition
- processus: Processus en cours et calendrier de d\xE9cision
- criteres: Crit\xE8res de choix du candidat
- forces: Forces et faiblesses de la candidature
- anglais: Niveau d'anglais
- specificites: Sp\xE9cificit\xE9s si stagiaire ou alternant (synth\xE8se \xE9crite, d\xE9part \xE0 l'\xE9tranger, rythme, etc.)
- decision: Raison de la d\xE9cision finale
- synthese: Synth\xE8se globale

Pour le format de r\xE9ponse, tu dois fournir uniquement un objet JSON sans texte suppl\xE9mentaire.`
    };
    const userMessage = {
      role: "user",
      content: `Voici mes notes d'entretien. Analyse-les et g\xE9n\xE8re une synth\xE8se structur\xE9e selon le format demand\xE9 :

${notes}`
    };
    const responseText = await openAIService.getChatCompletionWithCache({
      messages: [systemMessage, userMessage],
      temperature: 0.7,
      maxTokens: 2e3,
      useSecondaryKey: true,
      // Utiliser le modèle secondaire (plus rapide)
      responseFormat: "json_object"
      // Demander explicitement un format JSON
    });
    let synthese;
    let cleanedResponse = responseText;
    const jsonRegex = /```json\s*([\s\S]*?)\s*```|```\s*([\s\S]*?)\s*```|\{[\s\S]*\}/gm;
    const match = jsonRegex.exec(responseText);
    if (match) {
      cleanedResponse = match[1] || match[2] || match[0];
    }
    console.log("R\xE9ponse re\xE7ue de l'API:", responseText);
    console.log("R\xE9ponse nettoy\xE9e:", cleanedResponse);
    try {
      synthese = JSON.parse(cleanedResponse);
      console.log("Objet JSON pars\xE9 avec succ\xE8s");
    } catch (error) {
      console.error("Erreur de parsing JSON:", error);
      console.error("Texte brut re\xE7u:", responseText);
      synthese = {
        synthese: "Impossible de g\xE9n\xE9rer une synth\xE8se structur\xE9e. Veuillez r\xE9essayer avec des notes plus d\xE9taill\xE9es.",
        error: "Erreur de format dans la r\xE9ponse"
      };
      return res.status(200).json({
        success: false,
        message: "La r\xE9ponse n'a pas pu \xEAtre structur\xE9e correctement",
        synthese
      });
    }
    return res.status(200).json({
      success: true,
      synthese
    });
  } catch (error) {
    console.error("Erreur lors de la g\xE9n\xE9ration de synth\xE8se:", error);
    return res.status(500).json({
      success: false,
      message: "Erreur interne du serveur"
    });
  }
}

