init_openai();
async function generateCyberFiche(req, res) {
  try {
    const { topic } = req.body;
    if (!topic || typeof topic !== "string" || topic.trim().length === 0) {
      return res.status(400).json({
        success: false,
        message: "Un sujet de fiche est requis"
      });
    }
    const systemPrompt = `Tu es un expert en cybers\xE9curit\xE9 charg\xE9 de cr\xE9er des fiches \xE9ducatives concises et structur\xE9es.
    G\xE9n\xE8re une fiche synth\xE9tique sur le sujet demand\xE9 en respectant STRICTEMENT cette structure :
    1. Un titre concis et clair (maximum 50 caract\xE8res)
    2. Une description courte du sujet (1-2 phrases, maximum 120 caract\xE8res)
    3. Un contenu au format Markdown avec EXACTEMENT ce format:
       - 2-3 sections principales maximum (niveau 2 avec ##)
       - Maximum 2 sous-sections par section (niveau 3 avec ###)
       - Paragraphes courts (3-4 lignes maximum)
       - Inclure uniquement des informations essentielles et pratiques
       - Mentionner 2-3 outils ou logiciels sp\xE9cifiques pertinents
       - \xC9viter toute statistique sauf si vraiment critique
       - Structure simple: d\xE9finition, explications, applications pratiques
    4. 3-5 points cl\xE9s \xE0 retenir (courts, une ligne par point)
    5. 2-3 r\xE9f\xE9rences pertinentes \xE0 consulter (noms pr\xE9cis)
    6. Une cat\xE9gorie parmi: menaces, vuln\xE9rabilit\xE9s, architecture, identit\xE9, d\xE9tection, gouvernance, personnalis\xE9
    7. Un niveau de complexit\xE9: d\xE9butant, interm\xE9diaire, avanc\xE9, tous niveaux
    
    R\xC8GLES IMPORTANTES:
    - Respecte EXACTEMENT ce format, sans variations
    - Sois concis et clair, \xE9vite tout contenu superflu
    - Pr\xE9sente uniquement les informations les plus essentielles
    - Inclus seulement des outils/solutions largement utilis\xE9s
    - Limite le contenu \xE0 ce qui est strictement n\xE9cessaire
    - Organise clairement l'information en sections et sous-sections
    
    R\xE9ponds uniquement avec un objet JSON valide (sans formatage de code Markdown), avec les cl\xE9s suivantes:
    {
      "title": "Titre de la fiche",
      "description": "Description br\xE8ve",
      "content": "Contenu au format Markdown",
      "keyPoints": ["Point cl\xE9 1", "Point cl\xE9 2", "Point cl\xE9 3"],
      "references": ["R\xE9f\xE9rence 1", "R\xE9f\xE9rence 2"],
      "category": "cat\xE9gorie",
      "level": "niveau"
    }`;
    const userPrompt = `Cr\xE9er une fiche de cybers\xE9curit\xE9 sur le sujet : ${topic}`;
    const messages = [
      { role: "system", content: systemPrompt },
      { role: "user", content: userPrompt }
    ];
    const result = await openAIService.getChatCompletionWithModel(messages, 0.7, 3e3, true);
    let cleanedResult = result;
    const backtickRegex = /```(?:json)?\s*([\s\S]*?)```/;
    const backtickMatch = result.match(backtickRegex);
    if (backtickMatch && backtickMatch[1]) {
      cleanedResult = backtickMatch[1].trim();
      console.log("Nettoyage des backticks effectu\xE9");
    }
    let ficheData;
    try {
      console.log("Tentative de parsing JSON:", cleanedResult);
      ficheData = JSON.parse(cleanedResult);
      console.log("Parsing JSON r\xE9ussi");
    } catch (error) {
      console.error("Impossible de parser la r\xE9ponse JSON de l'IA:", error);
      console.error("R\xE9ponse brute:", result);
      ficheData = {
        title: topic,
        description: "Fiche synth\xE9tique sur " + topic,
        content: result.includes("##") ? result : `## ${topic}

${result}`,
        keyPoints: ["Points importants sur ce sujet", "Outils et pratiques recommand\xE9s", "Consid\xE9rations de s\xE9curit\xE9"],
        references: ["Documentation technique", "Guides pratiques"],
        category: "personnalis\xE9",
        level: "interm\xE9diaire"
      };
    }
    const id = `gen-${Date.now()}-${Math.floor(Math.random() * 1e3)}`;
    return res.status(200).json({
      success: true,
      fiche: {
        id,
        title: ficheData.title,
        description: ficheData.description,
        content: ficheData.content,
        keyPoints: ficheData.keyPoints || [],
        references: ficheData.references || [],
        category: ficheData.category || "divers",
        level: ficheData.level || "interm\xE9diaire",
        icon: "BrainCircuit",
        isFavorite: false,
        hasBeenRead: false
      }
    });
  } catch (err) {
    const error = err;
    console.error("Erreur lors de la g\xE9n\xE9ration de la fiche:", error);
    return res.status(500).json({
      success: false,
      message: "Erreur lors de la g\xE9n\xE9ration de la fiche",
      error: error.message
    });
  }
}
