init_openai();
init_dbCacheService();
var glossaryTermsCache = /* @__PURE__ */ new Map();
var CACHE_EXPIRY = 60 * 60 * 1e3;
async function searchGlossaryTerm(req, res) {
  try {
    const { term } = req.body;
    if (!term) {
      return res.status(400).json({ success: false, message: "Le terme \xE0 rechercher est requis" });
    }
    const cacheKey = term.toLowerCase().trim();
    if (glossaryTermsCache.has(cacheKey)) {
      return res.status(200).json({ success: true, term: glossaryTermsCache.get(cacheKey) });
    }
    const dbCached = await getCached(cacheKey, "glossaire");
    if (dbCached) {
      try {
        const parsed = JSON.parse(dbCached);
        glossaryTermsCache.set(cacheKey, parsed);
        return res.status(200).json({ success: true, term: parsed });
      } catch {
      }
    }
    const termId = `gen-${Date.now()}-${cacheKey.replace(/[^a-z0-9]/g, "-")}`;
    const prompt = `Agis comme un expert en cybers\xE9curit\xE9 charg\xE9 de cr\xE9er des d\xE9finitions pr\xE9cises pour un glossaire visuel interactif. G\xE9n\xE8re une entr\xE9e de glossaire d\xE9taill\xE9e pour le terme "${term}". Le r\xE9sultat doit \xEAtre au format JSON avec les champs suivants :

{
  "term": "le terme en question",
  "acronym": "s'il s'agit d'un acronyme, sinon null",
  "definition": "d\xE9finition concise (max 2 phrases)",
  "extendedDefinition": "d\xE9finition plus d\xE9taill\xE9e (4-5 phrases)",
  "examples": ["exemple d'utilisation ou de contexte", "autre exemple si pertinent"],
  "category": "une des cat\xE9gories suivantes: threats, defense, tools, data, network, compliance",
  "tags": ["liste", "de", "mots-cl\xE9s", "associ\xE9s", "au", "terme"],
  "relatedTerms": ["liste vide pour maintenant"]
}

Important : La r\xE9ponse doit \xEAtre EXCLUSIVEMENT le JSON valide, sans intro, commentaire ou explication. Adapte la longueur et le d\xE9tail \xE0 l'importance du terme.`;
    const systemMessage = {
      role: "system",
      content: "Tu es un expert en cybers\xE9curit\xE9 charg\xE9 de cr\xE9er des d\xE9finitions pr\xE9cises pour un glossaire visuel interactif. R\xE9ponds uniquement avec du JSON valide."
    };
    const userMessage = {
      role: "user",
      content: prompt
    };
    const response = await openAIService.getChatCompletion([systemMessage, userMessage], 0.7, 1500);
    const parsedResponse = extractJsonFromOpenAiResponse(response);
    const defaultTermData = {
      term,
      acronym: null,
      definition: "D\xE9finition non disponible",
      extendedDefinition: "D\xE9finition d\xE9taill\xE9e non disponible",
      examples: [],
      category: "tools",
      tags: [term],
      relatedTerms: []
    };
    const termData = parsedResponse || defaultTermData;
    const glossaryTerm = {
      id: termId,
      ...termData,
      isFavorite: false,
      isBookmarked: false
    };
    glossaryTermsCache.set(cacheKey, glossaryTerm);
    await setCached(cacheKey, "glossaire", JSON.stringify(glossaryTerm));
    setTimeout(() => {
      glossaryTermsCache.delete(cacheKey);
    }, CACHE_EXPIRY);
    return res.status(200).json({ success: true, term: glossaryTerm });
  } catch (error) {
    console.error("Erreur lors de la g\xE9n\xE9ration du terme de glossaire:", error);
    return res.status(500).json({
      success: false,
      message: "Erreur lors de la g\xE9n\xE9ration du terme de glossaire",
      error: error.message || String(error)
    });
  }
}
