init_openai();
async function generateDebriefing(req, res) {
  try {
    const { userActions, correctApproach, scenario, performanceScore } = req.body;
    if (!userActions || !correctApproach || !scenario) {
      return res.status(400).json({
        error: "Donn\xE9es manquantes pour g\xE9n\xE9rer le d\xE9briefing"
      });
    }
    let scenarioContext;
    switch (scenario) {
      case "data_breach":
        scenarioContext = "fuite de donn\xE9es";
        break;
      case "ransomware":
        scenarioContext = "attaque par ransomware";
        break;
      case "phishing":
        scenarioContext = "tentative de phishing";
        break;
      case "insider_threat":
        scenarioContext = "menace interne";
        break;
      default:
        scenarioContext = "incident de cybers\xE9curit\xE9";
    }
    const systemPrompt = `
      Tu es un expert en cybers\xE9curit\xE9 charg\xE9 d'\xE9valuer une simulation d'enqu\xEAte sur une ${scenarioContext}.
      Ta mission est de fournir un d\xE9briefing \xE9ducatif qui aidera l'apprenant \xE0 d\xE9velopper ses comp\xE9tences.
      
      Fournir:
      1. Un r\xE9sum\xE9 de la performance de l'apprenant (bas\xE9 sur ses actions et son score final)
      2. Les points forts et les axes d'am\xE9lioration
      3. De 2 \xE0 3 le\xE7ons cl\xE9s \xE0 retenir de ce sc\xE9nario
      4. Un exemple anonymis\xE9 de cas r\xE9el similaire avec son impact (un Retour d'EXp\xE9rience - REX)
      5. Des ressources \xE0 consulter pour approfondir ce type de menace
      
      Format: organise le contenu en sections clairement d\xE9limit\xE9es, avec des titres en gras.
      Ton: informatif et constructif, jamais condescendant m\xEAme si le score est bas.
      Longueur: 300-400 mots au total.
    `;
    const userMessage = `
      Actions de l'utilisateur pendant la simulation:
      ${userActions.map((action) => `- ${action}`).join("\n")}
      
      Approche recommand\xE9e pour ce sc\xE9nario:
      ${correctApproach.map((step) => `- ${step}`).join("\n")}
      
      Type de sc\xE9nario: ${scenarioContext}
      Score de performance: ${performanceScore}/100
      
      G\xE9n\xE8re un d\xE9briefing \xE9ducatif complet pour cet apprenant.
    `;
    const completion = await openAIService.getChatCompletionSecondary({
      messages: [
        { role: "system", content: systemPrompt },
        { role: "user", content: userMessage }
      ],
      temperature: 0.7
    });
    if (!completion) {
      throw new Error("\xC9chec de la g\xE9n\xE9ration du d\xE9briefing");
    }
    const debriefingContent = completion.choices[0].message.content;
    return res.json({
      success: true,
      debriefing: debriefingContent
    });
  } catch (error) {
    console.error("Erreur lors de la g\xE9n\xE9ration du d\xE9briefing:", error);
    return res.status(500).json({
      error: "Erreur lors de la g\xE9n\xE9ration du d\xE9briefing",
      details: error instanceof Error ? error.message : "Erreur inconnue"
    });
  }
}
async function getContextualDocumentation(req, res) {
  try {
    const { context, term } = req.query;
    if (!context) {
      return res.status(400).json({
        error: "Contexte requis pour la documentation"
      });
    }
    let documents = getDocumentsFromKnowledgeBase(context);
    if (term) {
      const termLower = term.toLowerCase();
      documents = documents.filter(
        (doc) => doc.title.toLowerCase().includes(termLower) || doc.content.toLowerCase().includes(termLower)
      );
    }
    if (documents.length === 0) {
      try {
        const systemPrompt = `
          Tu es un expert en cybers\xE9curit\xE9 sp\xE9cialis\xE9 dans la cr\xE9ation de documentation technique.
          Produis une documentation pr\xE9cise, factuelle et \xE9ducative sur le sujet demand\xE9.
          Format: organise le contenu en sections avec des titres et sous-titres clairs.
          Ton: informatif et technique, accessible aux professionnels.
          Inclure: d\xE9finitions, enjeux, bonnes pratiques, et mesures de protection.
          
          R\xE9ponds avec un tableau de 2 \xE0 4 documents au format JSON. Chaque document doit avoir:
          1. Un titre concis
          2. Un contenu d\xE9taill\xE9 de 150-200 mots
          3. Une URL optionnelle vers une ressource externe pertinente (ANSSI, CNIL, etc.)
        `;
        const contextMap = {
          "data_breach": "fuites de donn\xE9es",
          "ransomware": "ran\xE7ongiciels",
          "phishing": "hame\xE7onnage",
          "insider_threat": "menaces internes",
          "social_engineering": "ing\xE9nierie sociale"
        };
        const contextLabel = contextMap[context] || context;
        const termLabel = term ? ` sur le terme sp\xE9cifique "${term}"` : "";
        const userMessage = `
          Je dois produire une documentation sur les ${contextLabel}${termLabel}.
          G\xE9n\xE8re 2 \xE0 4 documents informatifs sur ce sujet.
        `;
        const completion = await openAIService.getChatCompletionSecondary({
          messages: [
            { role: "system", content: systemPrompt },
            { role: "user", content: userMessage }
          ],
          temperature: 0.5
        });
        if (!completion) {
          throw new Error("\xC9chec de la g\xE9n\xE9ration de documentation");
        }
        const aiResponseContent = completion.choices[0].message.content;
        const jsonMatch = aiResponseContent.match(/```json\s*([\s\S]*?)\s*```/) || aiResponseContent.match(/\[\s*\{[\s\S]*\}\s*\]/);
        if (jsonMatch) {
          const jsonContent = jsonMatch[1] || jsonMatch[0];
          try {
            const parsedDocs = JSON.parse(jsonContent);
            if (Array.isArray(parsedDocs)) {
              documents = parsedDocs;
            } else {
              documents = [parsedDocs];
            }
          } catch (parseError) {
            documents = getFallbackDocumentation(context);
          }
        } else {
          documents = [
            {
              title: `Documentation sur ${contextLabel}`,
              content: aiResponseContent
            }
          ];
        }
      } catch (aiError) {
        console.error("Erreur IA, utilisation de la documentation de secours:", aiError);
        documents = getFallbackDocumentation(context);
      }
    }
    return res.json({
      success: true,
      documentation: documents
    });
  } catch (error) {
    console.error("Erreur lors de la r\xE9cup\xE9ration de la documentation:", error);
    return res.status(500).json({
      error: "Erreur lors de la r\xE9cup\xE9ration de la documentation",
      details: error instanceof Error ? error.message : "Erreur inconnue",
      documentation: getFallbackDocumentation(req.query.context)
    });
  }
}
