async function startDecisionFlow(req, res) {
  try {
    const { userId, topic } = req.body;
    if (!userId) {
      return res.status(400).json({ error: "ID utilisateur manquant" });
    }
    if (!expertSessions.has(userId)) {
      return res.status(404).json({ error: "Session expert non trouv\xE9e" });
    }
    let scenarios = await generateDecisionScenarios(userId, topic);
    const totalExchangesNeeded = 10;
    if (scenarios.length < totalExchangesNeeded) {
      const originalScenarios = [...scenarios];
      for (let i = scenarios.length; i < totalExchangesNeeded; i++) {
        const baseIndex = i % originalScenarios.length;
        const baseScenario = originalScenarios[baseIndex];
        const newScenario = {
          ...baseScenario,
          id: `scenario-${i + 1}`,
          situation: `Phase ${i + 1}: ${baseScenario.situation}`,
          context: `Suite aux d\xE9cisions pr\xE9c\xE9dentes, le budget a diminu\xE9. ${baseScenario.context}`
        };
        scenarios.push(newScenario);
      }
    }
    scenarios = scenarios.slice(0, totalExchangesNeeded);
    const decisionState = {
      userId,
      currentScenarioIndex: 0,
      scenarios,
      decisions: [],
      isInDecisionMode: true,
      remainingScenarios: totalExchangesNeeded
    };
    decisionStates.set(userId, decisionState);
    return res.status(200).json({
      success: true,
      scenario: scenarios[0],
      remainingScenarios: scenarios.length,
      currentScenario: 1
    });
  } catch (error) {
    console.error("Erreur lors de l'initialisation du flux de d\xE9cision:", error);
    return res.status(500).json({ error: "Erreur lors de l'initialisation du flux de d\xE9cision" });
  }
}
async function submitDecision(req, res) {
  try {
    const { userId, optionId } = req.body;
    if (!userId || !optionId) {
      return res.status(400).json({ error: "Param\xE8tres manquants" });
    }
    if (!decisionStates.has(userId)) {
      return res.status(404).json({ error: "Session de d\xE9cision non trouv\xE9e" });
    }
    const state = decisionStates.get(userId);
    const currentScenario = state.scenarios[state.currentScenarioIndex];
    state.decisions.push({
      scenarioId: currentScenario.id,
      optionId
    });
    if (state.currentScenarioIndex < state.scenarios.length - 1) {
      state.currentScenarioIndex++;
      state.remainingScenarios--;
      return res.status(200).json({
        success: true,
        scenario: state.scenarios[state.currentScenarioIndex],
        remainingScenarios: state.remainingScenarios,
        currentScenario: state.currentScenarioIndex + 1
      });
    } else {
      const summary = await generateDecisionSummary(userId, state);
      decisionStates.delete(userId);
      return res.status(200).json({
        success: true,
        isComplete: true,
        summary
      });
    }
  } catch (error) {
    console.error("Erreur lors de la soumission de la d\xE9cision:", error);
    return res.status(500).json({ error: "Erreur lors de la soumission de la d\xE9cision" });
  }
}
