async function generateDecisionSummary(userId, state) {
  try {
    const session3 = expertSessions.get(userId);
    if (!session3) {
      throw new Error("Session expert non trouv\xE9e");
    }
    const decisionsData = state.decisions.map((decision, index2) => {
      const scenario = state.scenarios.find((s) => s.id === decision.scenarioId);
      const option = scenario?.options.find((o) => o.id === decision.optionId);
      const otherOptions = scenario?.options.filter((o) => o.id !== decision.optionId);
      return {
        numero: index2 + 1,
        situation: scenario?.situation,
        contexte: scenario?.context,
        urgence: scenario?.urgencyLevel,
        choix: option?.text,
        description: option?.description,
        impacts: option?.impacts,
        alternativesNonChoisies: otherOptions?.map((o) => ({
          texte: o.text,
          impacts: o.impacts
        })),
        consequences: {
          security: option?.impacts.security === "positive" ? "Renforcement de la posture de s\xE9curit\xE9 de l'organisation" : option?.impacts.security === "negative" ? "Augmentation du risque d'incidents de s\xE9curit\xE9" : "Maintien du niveau de s\xE9curit\xE9 actuel",
          business: option?.impacts.business === "positive" ? "Am\xE9lioration des performances business et de la satisfaction des parties prenantes" : option?.impacts.business === "negative" ? "Impact n\xE9gatif sur les op\xE9rations et les objectifs commerciaux" : "Continuit\xE9 des op\xE9rations business avec ajustements mineurs",
          team: option?.impacts.team === "positive" ? "Renforcement de la coh\xE9sion d'\xE9quipe et du moral" : option?.impacts.team === "negative" ? "Tensions au sein de l'\xE9quipe et baisse potentielle de productivit\xE9" : "Stabilit\xE9 relative dans la dynamique d'\xE9quipe",
          legal: option?.impacts.legal === "positive" ? "Am\xE9lioration de la conformit\xE9 et r\xE9duction des risques juridiques" : option?.impacts.legal === "negative" ? "Exposition accrue aux risques l\xE9gaux et r\xE9glementaires" : "Maintien du statu quo en mati\xE8re de conformit\xE9",
          career: option?.impacts.career === "positive" ? "Impact positif sur votre r\xE9putation professionnelle et perspectives de carri\xE8re" : option?.impacts.career === "negative" ? "Potentiel impact n\xE9gatif sur votre position ou \xE9volution professionnelle" : "Effet neutre sur votre parcours professionnel"
        }
      };
    });
    const securityScore = decisionsData.reduce((score, decision) => score + (decision.impacts?.security === "positive" ? 1 : decision.impacts?.security === "negative" ? -1 : 0), 0);
    const businessScore = decisionsData.reduce((score, decision) => score + (decision.impacts?.business === "positive" ? 1 : decision.impacts?.business === "negative" ? -1 : 0), 0);
    const teamScore = decisionsData.reduce((score, decision) => score + (decision.impacts?.team === "positive" ? 1 : decision.impacts?.team === "negative" ? -1 : 0), 0);
    const legalScore = decisionsData.reduce((score, decision) => score + (decision.impacts?.legal === "positive" ? 1 : decision.impacts?.legal === "negative" ? -1 : 0), 0);
    const careerScore = decisionsData.reduce((score, decision) => score + (decision.impacts?.career === "positive" ? 1 : decision.impacts?.career === "negative" ? -1 : 0), 0);
    const profiles = {
      "Gardien de la S\xE9curit\xE9": securityScore > 0 && securityScore >= businessScore,
      "Strat\xE8ge Business": businessScore > 0 && businessScore > securityScore,
      "Leader d'\xC9quipe": teamScore > 0 && teamScore >= securityScore && teamScore >= businessScore,
      "Expert en Conformit\xE9": legalScore > 0 && legalScore >= securityScore && legalScore >= businessScore,
      "Diplomate Strat\xE9gique": Math.abs(securityScore) <= 1 && Math.abs(businessScore) <= 1 && Math.abs(teamScore) <= 1
    };
    const dominantProfile = Object.entries(profiles).filter(([_, value]) => value).map(([key, _]) => key)[0] || "Profil \xC9quilibr\xE9";
    const prompt = `
      Sujet: "${session3.topic || "cybers\xE9curit\xE9"}"
      
      L'utilisateur a termin\xE9 une s\xE9rie de sc\xE9narios de d\xE9cision en cybers\xE9curit\xE9 et a fait les choix suivants:
      
      ${JSON.stringify(decisionsData, null, 2)}
      
      Profil dominant identifi\xE9: ${dominantProfile}
      
      Scores par domaine:
      - S\xE9curit\xE9: ${securityScore}
      - Business: ${businessScore}
      - \xC9quipe: ${teamScore}
      - Conformit\xE9: ${legalScore}
      - Carri\xE8re: ${careerScore}
      
      G\xE9n\xE8re un r\xE9sum\xE9 d\xE9taill\xE9, personnalis\xE9 et analytique des d\xE9cisions prises par l'utilisateur, en incluant:
      
      1. Un profil de prise de d\xE9cision bas\xE9 sur les choix (en utilisant le profil dominant identifi\xE9)
      2. Une analyse sp\xE9cifique des cons\xE9quences des d\xE9cisions, sc\xE9nario par sc\xE9nario
      3. Une \xE9valuation des forces et faiblesses d\xE9montr\xE9es, avec des exemples concrets tir\xE9s des choix
      4. Des recommandations concr\xE8tes et actionnables pour am\xE9liorer la prise de d\xE9cision en cybers\xE9curit\xE9
      5. Un aper\xE7u de ce qui aurait pu se passer si d'autres choix avaient \xE9t\xE9 faits (chemins alternatifs)
      6. Une invitation \xE0 poursuivre la conversation avec l'expert cyber
      
      R\xE8gles importantes:
      - \xC9VITE absolument les marqueurs markdown comme ## ou *** dans ta r\xE9ponse
      - Utilise un langage simple et pr\xE9cis, sans jargon inutile
      - Structure ta r\xE9ponse en sections clairement d\xE9limit\xE9es mais sans utiliser de symboles de formatage markdown
      - Pour chaque sc\xE9nario, pr\xE9sente les cons\xE9quences R\xC9ELLES et D\xC9TAILL\xC9ES des choix, pas seulement les impacts g\xE9n\xE9riques
      - Mentionne des exemples concrets de sc\xE9narios r\xE9els similaires qui se sont produits dans l'industrie
      
      Format: Texte conversationnel, structur\xE9 en paragraphes courts et sections distinctes sans formatage markdown.
      Ton: Analytique mais encourageant, comme un mentor qui guide avec bienveillance.
    `;
    const messages = [
      { role: "system", content: "Tu es un expert en cybers\xE9curit\xE9 qui analyse la prise de d\xE9cision et fournit des conseils personnalis\xE9s." },
      { role: "user", content: prompt }
    ];
    return await openAIService.getChatCompletion(messages, 0.7);
  } catch (error) {
    console.error("Erreur lors de la g\xE9n\xE9ration du r\xE9sum\xE9 de d\xE9cision:", error);
    return "Analyse de vos d\xE9cisions: Vous avez fait face \xE0 des choix complexes qui refl\xE8tent les d\xE9fis r\xE9els de la cybers\xE9curit\xE9 moderne. Vos d\xE9cisions montrent une certaine approche de l'\xE9quilibre entre risques et b\xE9n\xE9fices. Pour continuer votre d\xE9veloppement, pensez \xE0 approfondir votre compr\xE9hension des impacts \xE0 long terme et \xE0 d\xE9velopper un cadre personnel de prise de d\xE9cision. Souhaitez-vous continuer \xE0 explorer ce sujet avec notre expert?";
  }
}

