init_openai();
async function generateDynamicChallenge(language, difficulty) {
  try {
    console.log(`G\xE9n\xE9ration d'un d\xE9fi ${language} de niveau ${difficulty}`);
    const systemPrompt = `Tu es un expert en programmation charg\xE9 de cr\xE9er des d\xE9fis de code pour un jeu \xE9ducatif appel\xE9 "Read Me If You Can".
      
    T\xC2CHE: G\xE9n\xE9rer un d\xE9fi de code complet en ${language === "python" ? "Python" : "SQL"} avec une difficult\xE9 "${difficulty}".

    NIVEAU DE DIFFICULT\xC9:
    - d\xE9butant: Concepts de base, syntaxe simple, op\xE9rations \xE9l\xE9mentaires
    - interm\xE9diaire: Combinaison de concepts, algorithmes simples, biblioth\xE8ques standard
    - avanc\xE9: Algorithmes complexes, concepts avanc\xE9s, optimisation

    FORMAT DE SORTIE (JSON):
    {
      "challenge": {
        "id": "auto-${language}-${difficulty}-${Date.now()}",
        "code": "string (code source \xE0 analyser)",
        "language": "${language}",
        "question": "string (question sur le code)",
        "difficulty": "${difficulty}",
        "responses": [
          {
            "id": "a",
            "text": "string (premi\xE8re option)",
            "isCorrect": boolean
          },
          {
            "id": "b",
            "text": "string (deuxi\xE8me option)",
            "isCorrect": boolean
          },
          {
            "id": "c",
            "text": "string (troisi\xE8me option)",
            "isCorrect": boolean
          },
          {
            "id": "d",
            "text": "string (quatri\xE8me option)",
            "isCorrect": boolean
          }
        ],
        "explanation": "string (explication d\xE9taill\xE9e)",
        "hint": "string (indice facultatif)"
      }
    }

    IMPORTANT:
    - Assure-toi qu'il y a exactement UNE seule r\xE9ponse correcte
    - Le d\xE9fi doit \xEAtre adapt\xE9 au niveau ${difficulty}
    - Assure-toi que le code est valide et sans erreur`;
    const response = await openAIService.getChatCompletion(
      [
        { role: "system", content: systemPrompt },
        { role: "user", content: `G\xE9n\xE8re un d\xE9fi de code ${language} de niveau ${difficulty}` }
      ],
      0.7,
      2e3
    );
    if (!response) {
      throw new Error("R\xE9ponse OpenAI vide");
    }
    try {
      const result = JSON.parse(response);
      if (!result.challenge) {
        throw new Error("Format de r\xE9ponse OpenAI invalide");
      }
      return {
        success: true,
        challenge: result.challenge
      };
    } catch (error) {
      console.error("Erreur lors du parsing de la r\xE9ponse OpenAI:", error);
      throw new Error("Erreur lors du parsing de la r\xE9ponse OpenAI");
    }
  } catch (error) {
    console.error("Erreur lors de la g\xE9n\xE9ration du d\xE9fi:", error);
    throw error;
  }
}

