async function generateFunctionalRequirements(inputs) {
  const systemPrompt = `Tu es un expert en assistance \xE0 ma\xEEtrise d'ouvrage (AMOA) sp\xE9cialis\xE9 dans la r\xE9daction d'expressions de besoins fonctionnels.
Tu dois produire un document structur\xE9, professionnel et complet \xE0 partir des informations fournies par l'utilisateur.
Le document doit \xEAtre structur\xE9 avec les sections suivantes:
1. CONTEXTE ET OBJECTIFS
2. P\xC9RIM\xC8TRE DU PROJET
3. PROCESSUS ACTUEL (si applicable)
4. BESOINS FONCTIONNELS
5. CAS D'USAGE PRINCIPAUX
6. CONTRAINTES ET EXIGENCES
7. CRIT\xC8RES DE SUCC\xC8S

Chaque section doit \xEAtre clairement identifi\xE9e et d\xE9taill\xE9e.
Ton style doit \xEAtre professionnel, pr\xE9cis et adapt\xE9 \xE0 un document officiel.
\xC9vite le jargon trop technique sauf si le contexte l'exige.
Utilise les informations fournies par l'utilisateur mais n'h\xE9site pas \xE0 enrichir le document avec des consid\xE9rations pertinentes que l'utilisateur aurait pu omettre.
R\xE9ponds uniquement avec le document format\xE9, sans commentaires suppl\xE9mentaires.`;
  const userPrompt = `Voici les informations pour g\xE9n\xE9rer l'expression de besoin fonctionnel :
- Contexte du projet : ${inputs["context"] || "Non sp\xE9cifi\xE9"}
- Besoin m\xE9tier principal : ${inputs["business-need"] || "Non sp\xE9cifi\xE9"}
- Processus actuel : ${inputs["current-process"] || "Non sp\xE9cifi\xE9"}
- Types d'utilisateurs concern\xE9s : ${inputs["user-types"] || "Non sp\xE9cifi\xE9"}
- Contraintes particuli\xE8res : ${inputs["constraints"] || "Non sp\xE9cifi\xE9"}

G\xE9n\xE8re un document complet et structur\xE9 d'expression de besoin fonctionnel \xE0 partir de ces informations.`;
  const messages = [
    { role: "system", content: systemPrompt },
    { role: "user", content: userPrompt }
  ];
  const content = await openAIService.getChatCompletion(messages, false, 0.7, 2500);
  const sections = [];
  const lines = content.split("\n");
  let currentSection = null;
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    if (/^\d+\.\s+[A-ZÉÈÊËÀÂÔÙÛÇÑ\s']+$/.test(line)) {
      if (currentSection) {
        sections.push(currentSection);
      }
      currentSection = {
        title: line,
        content: ""
      };
    } else if (currentSection) {
      currentSection.content += (currentSection.content ? "\n" : "") + line;
    }
  }
  if (currentSection) {
    sections.push(currentSection);
  }
  return {
    content,
    sections
  };
}
