async function generatePromptExamples(req, res) {
  try {
    const { language = "general", count = 3 } = req.body;
    const userId = req.headers["x-user-id"] ? parseInt(req.headers["x-user-id"]) : void 0;
    const key = `user:${userId || "anonymous"}`;
    const allowed = await rateLimiterService.check(key, "developement");
    if (!allowed) {
      return res.status(429).json({
        error: "Limite de requ\xEAtes atteinte",
        retryAfter: 60
        // Attendre 60 secondes par défaut
      });
    }
    const cacheKey = `prompt_examples_${language}_${count}`;
    const cachedExamples = await simpleCacheService.get(cacheKey, "prompt_examples");
    if (cachedExamples) {
      await simpleCacheService.logCacheHit("prompt_examples", "Exemples de prompts");
      return res.json({ examples: JSON.parse(cachedExamples) });
    }
    const systemPrompt = `Tu es un expert en programmation et en g\xE9n\xE9ration de code, sp\xE9cialis\xE9 dans Python, SQL et les formules Excel. G\xE9n\xE8re ${count} id\xE9es de projets ou de fonctionnalit\xE9s de code que quelqu'un pourrait vouloir impl\xE9menter.`;
    let userPrompt = "";
    if (language === "python") {
      userPrompt = `G\xE9n\xE8re des id\xE9es cr\xE9atives et pratiques pour des scripts Python, en te concentrant sur l'analyse de donn\xE9es, l'automatisation, les algorithmes, et la science des donn\xE9es.`;
    } else if (language === "sql") {
      userPrompt = `G\xE9n\xE8re des id\xE9es r\xE9alistes de requ\xEAtes SQL pour l'analyse de donn\xE9es, les rapports commerciaux, la gestion de bases de donn\xE9es et l'optimisation de performances.`;
    } else if (language === "excel") {
      userPrompt = `G\xE9n\xE8re des id\xE9es pratiques de formules Excel pour l'analyse financi\xE8re, la gestion de donn\xE9es, les tableaux de bord et les calculs statistiques.`;
    } else {
      userPrompt = `G\xE9n\xE8re des id\xE9es cr\xE9atives et pratiques pour des scripts Python, des requ\xEAtes SQL et des formules Excel.`;
    }
    userPrompt += ` Les id\xE9es doivent \xEAtre formul\xE9es comme des instructions concises pour un g\xE9n\xE9rateur de code, pr\xE9fix\xE9es par le nom du langage appropri\xE9 (Python, SQL ou Excel).
    
R\xE9ponds uniquement avec un tableau JSON d'id\xE9es, sans explications suppl\xE9mentaires. Format: {"ideas": ["Python: analyse de donn\xE9es CSV", "SQL: requ\xEAte de ventes", "Excel: formule pour budget", ...]}`;
    try {
      const response = await openai.chat.completions.create({
        messages: [
          { role: "system", content: systemPrompt },
          { role: "user", content: userPrompt }
        ],
        response_format: { type: "json_object" },
        temperature: 0.8,
        max_tokens: 1e3
      });
      let examples = [];
      try {
        const content = response.choices[0]?.message?.content || "{}";
        const parsedContent = JSON.parse(content);
        if (Array.isArray(parsedContent.ideas)) {
          examples = parsedContent.ideas;
        } else if (Array.isArray(parsedContent)) {
          examples = parsedContent;
        } else {
          throw new Error("Invalid response structure");
        }
      } catch (parseError) {
        console.error("Error parsing examples:", parseError);
        examples = [
          "Python: Cr\xE9er un script d'analyse de donn\xE9es CSV avec graphiques",
          "SQL: Requ\xEAte pour analyser les ventes mensuelles par r\xE9gion et produit",
          "Excel: Formule pour calculer des projections financi\xE8res sur 5 ans"
        ];
      }
      await simpleCacheService.set(cacheKey, JSON.stringify(examples), 60 * 60, "prompt_examples", "G\xE9n\xE9ration d'exemples");
      await simpleCacheService.logCacheMiss("prompt_examples", "Exemples de prompts");
      res.json({ examples });
    } catch (aiError) {
      console.error("OpenAI API error:", aiError);
      res.status(500).json({
        error: "Error generating examples",
        examples: [
          "Python: Cr\xE9er un script d'analyse de donn\xE9es CSV avec graphiques",
          "SQL: Requ\xEAte pour analyser les ventes mensuelles par r\xE9gion et produit",
          "Excel: Formule pour calculer des projections financi\xE8res sur 5 ans"
        ]
      });
    }
  } catch (error) {
    console.error("Error generating prompt examples:", error);
    res.status(500).json({
      error: "An error occurred while generating prompt examples",
      examples: [
        "Python: Cr\xE9er un script d'analyse de donn\xE9es CSV avec graphiques",
        "SQL: Requ\xEAte pour analyser les ventes mensuelles par r\xE9gion et produit",
        "Excel: Formule pour calculer des projections financi\xE8res sur 5 ans"
      ]
    });
  }
}
