async function executeGeneratedCode(req, res) {
  try {
    const { code, language } = req.body;
    if (!code || !language) {
      return res.status(400).json({ error: "Code ou langage manquant" });
    }
    const userId = req.headers["x-user-id"] ? parseInt(req.headers["x-user-id"]) : void 0;
    const rateLimitResult = await rateLimiterService.checkRateLimit({
      userId: userId || 0,
      endpoint: "/api/code-generator/execute",
      actionType: "execute_code",
      req
    });
    if (!rateLimitResult.allowed) {
      return res.status(429).json({
        error: "Limite de requ\xEAtes atteinte",
        retryAfter: rateLimitResult.retryAfter,
        message: "Vous avez atteint la limite d'ex\xE9cution de code. Veuillez r\xE9essayer plus tard."
      });
    }
    const dangerousPatterns = [
      /process\.exit/i,
      /require\s*\(\s*['"]child_process['"]\s*\)/i,
      /exec\s*\(/i,
      /spawn\s*\(/i,
      /fork\s*\(/i,
      /fs\.(write|append|unlink|rmdir|rm|mkdir)/i,
      /process\.env/i,
      /rm\s+-rf/i,
      /http[s]?:\/\/evil\./i,
      /new\s+Function\s*\(/i,
      /eval\s*\(/i
    ];
    for (const pattern of dangerousPatterns) {
      if (pattern.test(code)) {
        return res.status(403).json({
          error: "Code potentiellement dangereux d\xE9tect\xE9",
          message: "Le code contient des instructions qui ne sont pas autoris\xE9es pour des raisons de s\xE9curit\xE9."
        });
      }
    }
    console.log(`Executing ${language} code in sandbox...`);
    const executionResult = await codeSandboxService.executeCode(code, language);
    console.log(`Code execution result: ${executionResult.success ? "success" : "error"}`);
    return res.json(executionResult);
  } catch (error) {
    console.error("Error executing generated code:", error);
    return res.status(500).json({
      error: "Erreur lors de l'ex\xE9cution du code",
      details: error instanceof Error ? error.message : "Unknown error",
      success: false,
      executionTimeMs: 0
    });
  }
}
async function improveGeneratedCode(req, res) {
  try {
    const { code, language, executionError, improvement } = req.body;
    if (!code || !language) {
      return res.status(400).json({ error: "Code ou langage manquant" });
    }
    const userId = req.headers["x-user-id"] ? parseInt(req.headers["x-user-id"]) : void 0;
    const rateLimitResult = await rateLimiterService.checkRateLimit({
      userId: userId || 0,
      endpoint: "/api/code-generator/improve",
      actionType: "improve_code",
      req
    });
    if (!rateLimitResult.allowed) {
      return res.status(429).json({
        error: "Limite de requ\xEAtes atteinte",
        retryAfter: rateLimitResult.retryAfter
      });
    }
    let improvementType = improvement || "optimize";
    let systemPrompt = `Tu es un expert en d\xE9veloppement logiciel sp\xE9cialis\xE9 dans l'am\xE9lioration de code ${language}.`;
    if (executionError) {
      improvementType = "fix";
      systemPrompt += `

Le code fourni produit l'erreur suivante lors de l'ex\xE9cution:
${executionError}

Corrige le code pour r\xE9soudre cette erreur.`;
    } else {
      switch (improvementType) {
        case "optimize":
          systemPrompt += `

Optimise le code fourni pour am\xE9liorer ses performances et sa lisibilit\xE9.`;
          break;
        case "simplify":
          systemPrompt += `

Simplifie le code fourni pour le rendre plus lisible et plus facile \xE0 maintenir.`;
          break;
        case "document":
          systemPrompt += `

Ajoute une documentation d\xE9taill\xE9e au code fourni, incluant des commentaires, des docstrings, et des exemples d'utilisation.`;
          break;
        case "test":
          systemPrompt += `

Ajoute des tests unitaires ou d'int\xE9gration complets pour le code fourni.`;
          break;
        default:
          systemPrompt += `

Am\xE9liore le code fourni en termes de qualit\xE9, lisibilit\xE9 et performances.`;
      }
    }
    systemPrompt += `

Ta r\xE9ponse doit \xEAtre un objet JSON avec la structure suivante:
    {
      "improvedCode": "Le code am\xE9lior\xE9",
      "explanation": "Une explication des am\xE9liorations apport\xE9es",
      "changesMade": ["Liste des modifications effectu\xE9es"]
    }`;
    const response = await openai.chat.completions.create({
      messages: [
        { role: "system", content: systemPrompt },
        { role: "user", content: `Voici le code ${language} \xE0 am\xE9liorer:

${code}` }
      ],
      response_format: { type: "json_object" },
      temperature: 0.3,
      max_tokens: 4e3
    });
    const content = response.choices[0].message.content;
    if (!content) {
      return res.status(500).json({ error: "\xC9chec de l'am\xE9lioration du code" });
    }
    try {
      const parsedResponse = JSON.parse(content);
      return res.json({
        ...parsedResponse,
        language,
        improvementType
      });
    } catch (error) {
      console.error("Error parsing OpenAI response:", error);
      return res.status(500).json({
        error: "Erreur lors du parsing de la r\xE9ponse",
        details: error instanceof Error ? error.message : "Unknown error"
      });
    }
  } catch (error) {
    console.error("Error improving generated code:", error);
    return res.status(500).json({
      error: "Erreur lors de l'am\xE9lioration du code",
      details: error instanceof Error ? error.message : "Unknown error"
    });
  }
}

