async function generateCyberPractices(req, res) {
  try {
    const count = parseInt(req.query.count) || 10;
    const systemPrompt = `Tu es un expert en cybers\xE9curit\xE9. G\xE9n\xE8re un ensemble de pratiques de cybers\xE9curit\xE9, 
    comprenant \xE0 la fois de bonnes et de mauvaises pratiques. 
    Pour chaque \xE9l\xE9ment, fournis le texte (court, max 6 mots), indique s'il s'agit d'une bonne pratique (true) 
    ou d'une mauvaise pratique (false), et une br\xE8ve explication (maximum 20 mots) sur pourquoi c'est une bonne ou 
    mauvaise pratique. R\xE9ponds UNIQUEMENT avec un tableau JSON sans aucun texte avant ou apr\xE8s.`;
    const userPrompt = `G\xE9n\xE8re exactement ${count} pratiques de cybers\xE9curit\xE9 al\xE9atoires, 
    avec exactement 50% de bonnes pratiques (isGood: true) et 50% de mauvaises pratiques (isGood: false). 
    
    Format attendu pour chaque pratique:
    {
      "text": "Courte description (max 6 mots)",
      "isGood": true/false,
      "explanation": "Explication courte (max 20 mots)"
    }
    
    R\xE9ponds uniquement avec un tableau JSON sans commentaires ni d\xE9limiteurs markdown, par exemple:
    [{"text":"Texte 1","isGood":true,"explanation":"Explication 1"},{"text":"Texte 2","isGood":false,"explanation":"Explication 2"}]`;
    const messages = [
      { role: "system", content: systemPrompt },
      { role: "user", content: userPrompt }
    ];
    const formattedMessages = messages.map((m) => {
      return {
        role: m.role,
        content: m.content
      };
    });
    const responseContent = await openAIService.getChatCompletion(
      formattedMessages,
      // Convertir le type pour éviter les erreurs
      0.7,
      // temperature
      1e3
      // maxTokens
    );
    if (!responseContent) {
      throw new Error("R\xE9ponse d'Azure OpenAI vide");
    }
    let cleanedResponse = responseContent.trim();
    if (cleanedResponse.startsWith("```json")) {
      cleanedResponse = cleanedResponse.replace(/^```json\n/, "").replace(/\n```$/, "");
    } else if (cleanedResponse.startsWith("```")) {
      cleanedResponse = cleanedResponse.replace(/^```\n/, "").replace(/\n```$/, "");
    }
    let practices;
    try {
      const jsonData = JSON.parse(cleanedResponse);
      if (jsonData.practices && Array.isArray(jsonData.practices)) {
        practices = jsonData.practices;
      } else if (Array.isArray(jsonData)) {
        practices = jsonData;
      } else {
        throw new Error("Structure de donn\xE9es incorrecte");
      }
    } catch (parseError) {
      console.error("Erreur de parsing JSON:", parseError);
      practices = [
        { text: "Mots de passe complexes", isGood: true, explanation: "Renforce la s\xE9curit\xE9 des comptes" },
        { text: "M\xEAme mot partout", isGood: false, explanation: "Risque de compromission multiple" },
        { text: "Mises \xE0 jour r\xE9guli\xE8res", isGood: true, explanation: "Corrige les vuln\xE9rabilit\xE9s connues" },
        { text: "Cliquer tous les liens", isGood: false, explanation: "Risque de phishing \xE9lev\xE9" },
        { text: "Authentification \xE0 deux facteurs", isGood: true, explanation: "Ajoute une couche de protection" }
      ];
    }
    res.json({
      success: true,
      practices
    });
  } catch (error) {
    console.error("Erreur lors de la g\xE9n\xE9ration des pratiques de cybers\xE9curit\xE9:", error);
    res.status(500).json({
      success: false,
      error: error.message || "Erreur lors de la g\xE9n\xE9ration des pratiques"
    });
  }
}

