init_openai();
async function chatWithCustomAssistant(req, res) {
  try {
    const {
      message,
      systemPrompt,
      assistantName,
      assistantPersonality,
      assistantDomain,
      history = []
    } = req.body;
    if (!message || !systemPrompt) {
      return res.status(400).json({
        success: false,
        message: "Le message et les instructions syst\xE8me sont requis"
      });
    }
    const conversationContext = [
      { role: "system", content: systemPrompt }
    ];
    if (history && history.length > 0) {
      history.forEach((msg) => {
        conversationContext.push({
          role: msg.role,
          content: msg.content
        });
      });
    }
    conversationContext.push({
      role: "user",
      content: message
    });
    const response = await openAIService.getChatCompletion(
      conversationContext,
      0.7,
      1500
    );
    const assistantResponse = response || "Je suis d\xE9sol\xE9, mais je n'ai pas pu g\xE9n\xE9rer une r\xE9ponse. Veuillez r\xE9essayer.";
    return res.status(200).json({
      success: true,
      response: assistantResponse
    });
  } catch (error) {
    console.error("Erreur lors de la g\xE9n\xE9ration de r\xE9ponse :", error);
    return res.status(500).json({
      success: false,
      message: "Une erreur est survenue lors de la g\xE9n\xE9ration de la r\xE9ponse"
    });
  }
}

