function buildPrompt(levelId, stepId, userResponse) {
  if (levelId === 5 && stepId >= 1 && stepId <= crisisManagementSteps.length) {
    const stepPrompt = crisisManagementSteps[stepId - 1].prompt;
    return stepPrompt.replace("{{userResponse}}", userResponse);
  }
  const level = ascensionLevels.find((l) => l.id === levelId);
  if (!level) {
    return "\xC9value la r\xE9ponse suivante de mani\xE8re constructive et \xE9ducative : " + userResponse;
  }
  return `${level.systemPrompt}

La r\xE9ponse de l'apprenant est : "${userResponse}"

Fournis une analyse d\xE9taill\xE9e avec points forts, points d'am\xE9lioration et recommandations.`;
}
async function analyzeUserResponse(req, res) {
  try {
    const { levelId, stepId, userResponse, context } = req.body;
    if (!userResponse || !levelId) {
      return res.status(400).json({
        success: false,
        message: "La r\xE9ponse utilisateur et l'ID du niveau sont requis"
      });
    }
    const systemPrompt = buildPrompt(levelId, stepId || 1, userResponse);
    const result = await openai2.chat.completions.create({
      model: deploymentName,
      messages: [
        { role: "system", content: systemPrompt },
        { role: "user", content: userResponse }
      ],
      temperature: 0.7,
      max_tokens: 1e3
    });
    if (!result.choices || result.choices.length === 0) {
      return res.status(500).json({
        success: false,
        message: "Aucune r\xE9ponse g\xE9n\xE9r\xE9e par l'IA"
      });
    }
    const aiResponse = result.choices[0].message?.content || "";
    return res.status(200).json({
      success: true,
      analysis: aiResponse,
      levelId,
      stepId: stepId || 1
    });
  } catch (error) {
    console.error("Erreur lors de l'analyse de la r\xE9ponse utilisateur:", error);
    return res.status(500).json({
      success: false,
      message: "Une erreur est survenue lors de l'analyse de la r\xE9ponse",
      error: error.message
    });
  }
}
async function getLevelInfo(req, res) {
  try {
    const { id } = req.params;
    const levelId = parseInt(id);
    if (isNaN(levelId)) {
      return res.status(400).json({
        success: false,
        message: "ID de niveau invalide"
      });
    }
    const level = ascensionLevels.find((l) => l.id === levelId);
    if (!level) {
      return res.status(404).json({
        success: false,
        message: "Niveau non trouv\xE9"
      });
    }
    let steps = [];
    if (levelId === 5) {
      steps = crisisManagementSteps.map((step) => ({
        id: step.id,
        title: step.title
      }));
    }
    return res.status(200).json({
      success: true,
      level: {
        id: level.id,
        title: level.title,
        theme: level.theme,
        steps
      }
    });
  } catch (error) {
    console.error("Erreur lors de la r\xE9cup\xE9ration des informations du niveau:", error);
    return res.status(500).json({
      success: false,
      message: "Une erreur est survenue lors de la r\xE9cup\xE9ration des informations du niveau",
      error: error.message
    });
  }
}
async function generateScenario(req, res) {
  try {
    const { levelId, difficulty } = req.body;
    if (!levelId) {
      return res.status(400).json({
        success: false,
        message: "L'ID du niveau est requis"
      });
    }
    const level = ascensionLevels.find((l) => l.id === levelId);
    if (!level) {
      return res.status(404).json({
        success: false,
        message: "Niveau non trouv\xE9"
      });
    }
    const systemPrompt = `Tu es un cr\xE9ateur de sc\xE9narios de formation en cybers\xE9curit\xE9 sp\xE9cialis\xE9 en ${level.theme}. 
    Cr\xE9e un sc\xE9nario d'apprentissage r\xE9aliste, immersif et d\xE9taill\xE9 pour une simulation interactive.
    
    Le sc\xE9nario doit inclure:
    1. Contexte d'entreprise r\xE9aliste (nom, secteur, taille)
    2. Situation initiale et d\xE9fi \xE0 relever
    3. Ressources disponibles pour l'apprenant
    4. Contraintes et difficult\xE9s sp\xE9cifiques
    5. Objectifs p\xE9dagogiques clairs
    
    La difficult\xE9 doit \xEAtre de niveau: ${difficulty || "interm\xE9diaire"}.
    
    R\xE9ponds au format JSON structur\xE9 comme suit:
    {
      "title": "Titre du sc\xE9nario",
      "context": {
        "companyName": "Nom de l'entreprise fictive",
        "sector": "Secteur d'activit\xE9",
        "size": "Taille (PME, grande entreprise, etc.)",
        "background": "Contexte d\xE9taill\xE9 de la situation"
      },
      "challenge": {
        "description": "Description du d\xE9fi \xE0 relever",
        "initialSituation": "Situation de d\xE9part",
        "objectives": ["Objectif 1", "Objectif 2", "etc."]
      },
      "resources": ["Ressource 1", "Ressource 2", "etc."],
      "constraints": ["Contrainte 1", "Contrainte 2", "etc."],
      "learningObjectives": ["Objectif p\xE9dagogique 1", "Objectif p\xE9dagogique 2", "etc."]
    }`;
    const result = await openai2.chat.completions.create({
      model: deploymentName,
      messages: [
        { role: "system", content: systemPrompt },
        { role: "user", content: `G\xE9n\xE8re un sc\xE9nario de formation en ${level.theme} de difficult\xE9 ${difficulty || "interm\xE9diaire"}.` }
      ],
      temperature: 0.8,
      max_tokens: 1500,
      response_format: { type: "json_object" }
    });
    if (!result.choices || result.choices.length === 0) {
      return res.status(500).json({
        success: false,
        message: "Aucun sc\xE9nario g\xE9n\xE9r\xE9 par l'IA"
      });
    }
    const scenarioString = result.choices[0].message?.content || "{}";
    const scenario = JSON.parse(scenarioString);
    return res.status(200).json({
      success: true,
      scenario,
      levelId
    });
  } catch (error) {
    console.error("Erreur lors de la g\xE9n\xE9ration du sc\xE9nario:", error);
    return res.status(500).json({
      success: false,
      message: "Une erreur est survenue lors de la g\xE9n\xE9ration du sc\xE9nario",
      error: error.message
    });
  }
}
