async function generateInvestigationNotes(req, res) {
  try {
    const { prompt, evidences, suspects, currentLevel } = req.body;
    if (!prompt) {
      return res.status(400).json({ success: false, error: "Prompt requis pour g\xE9n\xE9rer du contenu" });
    }
    const messages = [
      {
        role: "system",
        content: `Tu es un expert en investigation de cybers\xE9curit\xE9 sp\xE9cialis\xE9 dans l'analyse des fuites de donn\xE9es. 
        Tu aides l'utilisateur \xE0 g\xE9n\xE9rer des notes d'enqu\xEAte structur\xE9es et pertinentes pour le niveau ${currentLevel || "D\xE9butant"}.
        Ton analyse doit \xEAtre m\xE9thodique, pr\xE9cise et bas\xE9e sur les \xE9l\xE9ments de preuve.
        IMPORTANT: Ne jamais commencer par "Voici une analyse" ou similaire, r\xE9dige directement le contenu comme si c'\xE9tait les notes de l'utilisateur.`
      },
      {
        role: "user",
        content: `${prompt}
        
        ${evidences ? `Voici les preuves que j'ai analys\xE9es jusqu'\xE0 pr\xE9sent:
        ${JSON.stringify(evidences, null, 2)}` : ""}
        
        ${suspects ? `Voici les suspects identifi\xE9s:
        ${JSON.stringify(suspects, null, 2)}` : ""}`
      }
    ];
    const notesContent = await openAIService.getChatCompletionWithModel(
      messages,
      0.7,
      1500,
      true
      // Utiliser GPT-4o au lieu de GPT-4o-mini
    );
    return res.json({
      success: true,
      content: notesContent
    });
  } catch (error) {
    console.error("Erreur lors de la g\xE9n\xE9ration des notes:", error);
    return res.status(500).json({
      success: false,
      error: "Erreur lors de la g\xE9n\xE9ration des notes d'enqu\xEAte"
    });
  }
}
async function analyzeEvidence(req, res) {
  try {
    const { evidenceId, evidenceContent, caseContext, userNotes } = req.body;
    if (!evidenceId || !evidenceContent) {
      return res.status(400).json({
        error: "Param\xE8tres manquants"
      });
    }
    const messages = [
      {
        role: "system",
        content: `Tu es un expert en investigation num\xE9rique et cybers\xE9curit\xE9, sp\xE9cialis\xE9 dans l'analyse des fuites de donn\xE9es. 
        Tu aides un apprenti enqu\xEAteur \xE0 analyser des preuves num\xE9riques dans un sc\xE9nario \xE9ducatif.
        
        Tu dois analyser la preuve fournie et donner une analyse professionnelle qui:
        1. Explique en d\xE9tail ce que r\xE9v\xE8le la preuve
        2. Identifie des \xE9l\xE9ments suspects ou pertinents que l'enqu\xEAteur pourrait avoir manqu\xE9s
        3. Fait des connexions avec d'autres \xE9l\xE9ments potentiels de l'enqu\xEAte
        4. Explique l'importance de ce type de preuve dans des enqu\xEAtes r\xE9elles
        5. Fournit des conseils p\xE9dagogiques sur les meilleures pratiques d'analyse

        R\xE9ponds dans un format structur\xE9 et professionnel, comme un v\xE9ritable expert en cybers\xE9curit\xE9.
        Ta r\xE9ponse doit \xEAtre p\xE9dagogique et instructive tout en restant accessible.`
      },
      {
        role: "user",
        content: `Voici une preuve dans le cadre d'une enqu\xEAte sur une fuite de donn\xE9es confidentielles:
        
        ID de la preuve: ${evidenceId}
        
        Contenu:
        ${evidenceContent}
        
        Contexte de l'enqu\xEAte: ${caseContext || "Enqu\xEAte sur une fuite de donn\xE9es confidentielles dans une entreprise tech."}
        
        ${userNotes ? `Mes notes actuelles: ${userNotes}` : ""}
        
        Merci de fournir une analyse compl\xE8te de cette preuve.`
      }
    ];
    const analysisContent = await openAIService.getChatCompletion(
      messages,
      0.7,
      1500
    );
    return res.status(200).json({
      success: true,
      analysis: analysisContent
    });
  } catch (error) {
    const errorMessage = error instanceof Error ? error.message : "Erreur inconnue";
    console.error("Erreur lors de l'analyse IA des preuves:", error);
    return res.status(500).json({
      error: "Erreur lors de l'analyse des preuves",
      details: errorMessage
    });
  }
}
