async function evaluateCodeSubmission(instructions, expectedSolution, userCode) {
  try {
    const response = await openAIService.getChatCompletion(
      [
        {
          role: "system",
          content: `Tu es un \xE9valuateur de code expert. \xC9value la solution soumise par rapport \xE0 la solution attendue.
          Sois juste, informatif et p\xE9dagogique. Fournis un score sur 100 et un feedback constructif.`
        },
        {
          role: "user",
          content: `Instructions de l'exercice: "${instructions}"
          
          Solution attendue:
          \`\`\`
          ${expectedSolution}
          \`\`\`
          
          Code soumis par l'utilisateur:
          \`\`\`
          ${userCode}
          \`\`\`
          
          \xC9value le code soumis en v\xE9rifiant s'il r\xE9pond aux exigences et fonctionne comme la solution attendue.
          Fournis une r\xE9ponse JSON avec:
          1. isCorrect: boolean indiquant si la solution est globalement correcte
          2. score: nombre entre 0 et 100 
          3. feedback: feedback d\xE9taill\xE9 sur la solution
          4. suggestions: suggestions d'am\xE9lioration (si n\xE9cessaire)`
        }
      ],
      true,
      // utiliser le modèle secondaire
      0.7,
      // temperature
      1e3,
      // max_tokens
      { responseFormat: "json_object" }
      // demander une réponse en format JSON
    );
    if (!response) {
      throw new Error("Aucune \xE9valuation g\xE9n\xE9r\xE9e");
    }
    const evaluation = JSON.parse(response);
    return {
      isCorrect: evaluation.isCorrect || false,
      score: evaluation.score || 0,
      feedback: evaluation.feedback || "Pas de feedback disponible.",
      suggestions: evaluation.suggestions
    };
  } catch (error) {
    console.error("Erreur lors de l'\xE9valuation du code:", error);
    return {
      isCorrect: false,
      score: 0,
      feedback: "Impossible d'\xE9valuer le code. Veuillez r\xE9essayer."
    };
  }
}
