function getCachedQuestions(category, difficulty, exerciseType) {
  const cache = questionCaches.find(
    (c) => c.category === category && c.difficulty === difficulty && c.exerciseType === exerciseType && Date.now() - c.timestamp < CACHE_EXPIRY3
  );
  return cache ? cache.questions : [];
}
function cacheQuestions(questions, category, difficulty, exerciseType) {
  const existingCacheIndex = questionCaches.findIndex(
    (c) => c.category === category && c.difficulty === difficulty && c.exerciseType === exerciseType
  );
  if (existingCacheIndex !== -1) {
    questionCaches.splice(existingCacheIndex, 1);
  }
  questionCaches.push({
    questions,
    category,
    difficulty,
    exerciseType,
    timestamp: Date.now()
  });
}
