function getUrgencyLevel(domain, difficulty, stage = 0) {
  const stageMultiplier = Math.min(stage, 3) * 0.25;
  let baseUrgency = 0;
  if (domain.toLowerCase().includes("crise") || domain.toLowerCase().includes("incident")) {
    baseUrgency = 0.75;
  } else if (difficulty === "Expert") {
    baseUrgency = 0.5;
  } else if (difficulty === "Interm\xE9diaire") {
    baseUrgency = 0.25;
  } else {
    baseUrgency = 0;
  }
  const urgencyScore = Math.min(Math.max(baseUrgency + stageMultiplier, 0), 1);
  if (urgencyScore >= 0.75) {
    return "\xE9lev\xE9, n\xE9cessitant une r\xE9ponse rapide";
  } else if (urgencyScore >= 0.5) {
    return "mod\xE9r\xE9, avec un certain sentiment d'urgence";
  } else if (urgencyScore >= 0.25) {
    return "mod\xE9r\xE9, avec un d\xE9lai raisonnable pour r\xE9pondre";
  } else {
    return "normal, permettant une r\xE9flexion approfondie";
  }
}
